<?php
namespace Tests\Feature;
use App\Models\{AiSummary,AiUsageLog,Task,TaskChecklist,User,Workspace};use App\Services\AI\AiService;use App\Support\CurrentWorkspace;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\Http;use Tests\TestCase;
class AiMvpTest extends TestCase{use RefreshDatabase;private function member(bool $enabled=true):array{$u=User::create(['name'=>'Owner','email'=>fake()->unique()->safeEmail(),'password'=>'password','status'=>'active']);$w=Workspace::create(['uuid'=>(string)str()->uuid(),'name'=>'Acme','slug'=>'acme'.uniqid(),'status'=>'active','owner_id'=>$u->id,'edition'=>'saas']);$w->users()->attach($u->id,['role_key'=>'workspace_owner','status'=>'active','joined_at'=>now()]);$w->settings()->create(['company_name'=>'Acme','timezone'=>'UTC','currency'=>'USD','ai_enabled'=>$enabled,'feature_flags'=>['ai_preferred_provider'=>'local','ai_enabled'=>true,'local_ai'=>true]]);app(CurrentWorkspace::class)->set($w);config(['workproof.features.ai_enabled'=>true,'workproof.features.local_ai'=>true,'ai.default_provider'=>'local']);return[$u,$w->fresh('settings')];}private function asTenant($u,$w){return $this->actingAs($u)->withSession(['current_workspace_id'=>$w->id]);}private function fakeAi(string $text='Generated suggestion'):void{Http::fake(['*/api/generate'=>Http::response(['response'=>$text,'prompt_eval_count'=>10,'eval_count'=>12],200)]);}public function test_ai_blocked_when_workspace_ai_disabled():void{[$u,$w]=$this->member(false);$res=app(AiService::class)->generate($w,'task_cleaner','prompt');$this->assertFalse($res->success);$this->assertDatabaseHas('ai_usage_logs',['workspace_id'=>$w->id,'status'=>'blocked']);}public function test_ai_usage_logged_on_success():void{[$u,$w]=$this->member();$this->fakeAi();$res=app(AiService::class)->generate($w,'task_cleaner','prompt');$this->assertTrue($res->success);$this->assertDatabaseHas('ai_usage_logs',['workspace_id'=>$w->id,'status'=>'success','provider'=>'ollama']);}public function test_ai_usage_logged_on_failure_and_does_not_crash():void{[$u,$w]=$this->member();Http::fake(['*/api/generate'=>Http::response([],500)]);$res=app(AiService::class)->generate($w,'risk_summary','prompt');$this->assertFalse($res->success);$this->assertDatabaseHas('ai_usage_logs',['workspace_id'=>$w->id,'status'=>'failed']);}public function test_ai_daily_summary_saves_ai_summaries():void{[$u,$w]=$this->member();$this->fakeAi('Daily summary citing report IDs.');$this->asTenant($u,$w)->postJson('/ai/daily-report-summary',['date'=>today()->toDateString()])->assertOk()->assertJson(['success'=>true]);$this->assertDatabaseHas('ai_summaries',['workspace_id'=>$w->id,'summary_type'=>'daily_report_summary']);}public function test_task_cleaner_returns_structured_suggestion():void{[$u,$w]=$this->member();$this->fakeAi('{"cleaned_title":"Ship","suggested_checklist_items":["Review"]}');$this->asTenant($u,$w)->postJson('/ai/task-cleaner',['raw_text'=>'ship this'])->assertOk()->assertJson(['success'=>true])->assertSee('cleaned_title');}public function test_checklist_generator_does_not_auto_add_until_accepted():void{[$u,$w]=$this->member();$task=Task::create(['title'=>'Work','priority'=>'medium','status'=>'new','created_by'=>$u->id]);$this->fakeAi('["One"]');$this->asTenant($u,$w)->postJson('/ai/checklist-generator',['task_id'=>$task->id])->assertOk();$this->assertSame(0,TaskChecklist::count());$this->asTenant($u,$w)->post("/tasks/{$task->id}/ai-checklist/accept",['items'=>['One']])->assertRedirect();$this->assertDatabaseHas('task_checklists',['task_id'=>$task->id,'title'=>'One']);}public function test_ai_quota_blocks_when_exceeded():void{[$u,$w]=$this->member();$w->settings->update(['feature_flags'=>['ai_preferred_provider'=>'cloud','ai_enabled'=>true,'ai_monthly_quota'=>1]]);config(['workproof.features.ai_enabled'=>true,'ai.monthly_quota_enabled'=>true]);AiUsageLog::create(['workspace_id'=>$w->id,'feature'=>'x','status'=>'success','created_at'=>now()]);$res=app(AiService::class)->generate($w->fresh('settings'),'task_cleaner','prompt',[],['provider'=>'cloud']);$this->assertFalse($res->success);$this->assertDatabaseHas('ai_usage_logs',['workspace_id'=>$w->id,'status'=>'blocked']);}public function test_workspace_a_cannot_see_workspace_b_ai_summaries():void{[$a,$wa]=$this->member();[$b,$wb]=$this->member();AiSummary::withoutWorkspaceScope()->create(['workspace_id'=>$wb->id,'summary_type'=>'risk_summary','content'=>'Secret']);$this->asTenant($a,$wa)->get('/ai-summary')->assertOk()->assertDontSee('Secret');}public function test_platform_admin_can_view_ai_usage_page():void{$admin=User::create(['name'=>'Admin','email'=>'admin@example.com','password'=>'password','status'=>'active','is_platform_admin'=>true]);$this->actingAs($admin)->get('/ai-usage')->assertOk()->assertSee('AI Usage');}}
